 2	
 3	import SectionHeading from '@components/headers/SectionHeading';
 4	import { Alert, AlertVariant, HelperText, HelperTextItem } from '@patternfly/react-core';
 5	import { useForkliftTranslation } from '@utils/i18n';
 6	
 7	type ProvidersCreatePageHeaderProps = {
 8	  apiError: Error | null | undefined;
 9	};
10	
11	const ProvidersCreatePageHeader: FC<ProvidersCreatePageHeaderProps> = ({ apiError }) => {
12	  const { t } = useForkliftTranslation();
13	
14	  return (
15	    <>
16	      <SectionHeading text={t('Create provider')} />
17	
18	      <HelperText>
19	        <HelperTextItem variant="default">
20	          {t(
21	            'Create providers by using the form below. Providers CRs store attributes that enable MTV to connect to and interact with the source and target providers.',
22	          )}
23	        </HelperTextItem>
24	      </HelperText>
25	
26	      {apiError && (
27	        <Alert
28	          className="co-alert co-alert--margin-top"
29	          isInline
30	          variant={AlertVariant.danger}
31	          title={t('Error')}
32	        >
33	          {apiError?.message || apiError?.toString()}
34	        </Alert>
35	      )}
36	    </>
37	  );
38	};
39	
40	export default ProvidersCreatePageHeader;

